  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
  4→import { sortPhases } from '@/domain/phaseModels';
  5→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  6→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  7→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  8→
  9→const ProjectContext = createContext(null);
 10→const HISTORY_LIMIT = 100;
 11→
 12→function snapshotProject(project) {
 13→  return JSON.stringify(project);
 14→}
 15→
 16→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 17→  const nextSnapshot = snapshotProject(nextProject);
 18→  const history = recordHistory
 19→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 20→    : state.history;
 21→
 22→  return {
 23→    ...state,
 24→    history,
 25→    future: recordHistory ? [] : state.future,
 26→    project: nextProject,
 27→    isDirty: nextSnapshot !== state.savedSnapshot,
 28→  };
 29→}
 30→
 31→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 32→  const nextFloors = state.project.floors.map((floor) => (
 33→    floor.id === floorId ? updater(floor) : floor
 34→  ));
 35→
 36→  return applyProjectUpdate(state, {
 37→    ...state.project,
 38→    updatedAt: new Date().toISOString(),
 39→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 40→  }, recordHistory);
 41→}
 42→
 43→function replaceFloors(state, floors, recordHistory = true) {
 44→  return applyProjectUpdate(state, {
 45→    ...state.project,
 46→    updatedAt: new Date().toISOString(),
 47→    floors: sortFloors(floors),
 48→  }, recordHistory);
 49→}
 50→
 51→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 52→  return {
 53→    ...project,
 54→    floors: project.floors.map((floor) => ({
 55→      ...floor,
 56→      stairs: (floor.stairs || []).map((stair) => ({
 57→        ...stair,
 58→        floorRelation: {
 59→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 60→            ? fallbackFloorId
 61→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 62→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 63→            ? fallbackFloorId
 64→            : (stair.floorRelation?.toFloorId ?? floor.id),
 65→        },
 66→      })),
 67→    })),
 68→    sheets: (project.sheets || []).map((sheet) => ({
 69→      ...sheet,
 70→      viewports: (sheet.viewports || []).map((viewport) => ({
 71→        ...viewport,
 72→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 73→          ? fallbackFloorId
 74→          : viewport.sourceFloorId,
 75→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 76→          ? null
 77→          : viewport.sourceRefId,
 78→      })),
 79→    })),
 80→  };
 81→}
 82→
 83→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 84→  const nextWall = { ...existingWall, ...wallUpdate };
 85→
 86→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 87→    nextWall.startAttachment = null;
 88→  }
 89→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 90→    nextWall.endAttachment = null;
 91→  }
 92→
 93→  return syncWallAttachmentPoints(nextWall, columns);
 94→}
 95→
 96→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 97→  return openings.map((opening) => {
 98→    if (opening.wallId !== wallId) return opening;
 99→
100→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
101→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
102→  });
103→}
104→
105→function projectReducer(state, action) {
106→  switch (action.type) {
107→    case 'PROJECT_NEW': {
108→      const newProject = {
109→        ...action.project,
110→        floors: sortFloors(action.project.floors || []),
111→      };
112→      return {
113→        project: newProject,
114→        isDirty: false,
115→        lastSavedAt: null,
116→        savedSnapshot: snapshotProject(newProject),
117→        history: [],
118→        future: [],
119→      };
120→    }
121→
122→    case 'PROJECT_LOAD': {
123→      const loadedProject = {
124→        ...action.project,
125→        floors: sortFloors(action.project.floors || []),
126→      };
127→      return {
128→        project: loadedProject,
129→        isDirty: false,
130→        lastSavedAt: action.savedAt || null,
131→        savedSnapshot: snapshotProject(loadedProject),
132→        history: [],
133→        future: [],
134→      };
135→    }
136→
137→    case 'PROJECT_SET_NAME':
138→      return applyProjectUpdate(state, {
139→        ...state.project,
140→        name: action.name,
141→        updatedAt: new Date().toISOString(),
142→      });
143→
144→    case 'PROJECT_UPDATE':
145→      return applyProjectUpdate(state, {
146→        ...state.project,
147→        ...action.updates,
148→        updatedAt: new Date().toISOString(),
149→      });
150→
151→    case 'FLOOR_ADD':
152→      return replaceFloors(state, [...state.project.floors, action.floor]);
153→
154→    case 'FLOOR_UPDATE':
155→      return updateFloor(state, action.floor.id, (floor) => {
156→        const mergedFloor = {
157→          ...floor,
158→          ...action.floor,
159→        };
160→        const nextElevation = getFloorElevation(mergedFloor);
161→        const deltaElevation = nextElevation - getFloorElevation(floor);
162→        return {
163→          ...shiftFloorAbsoluteElements({
164→            ...mergedFloor,
165→            elevation: getFloorElevation(floor),
166→          }, deltaElevation),
167→          elevation: nextElevation,
168→        };
169→      }, true, { sort: true });
170→
171→    case 'FLOOR_DUPLICATE': {
172→      const duplicatedFloor = action.floor;
173→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
174→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
175→
176→      const shiftedFloors = state.project.floors.map((floor) => {
177→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
178→
179→        const previousLevelIndex = getFloorLevelIndex(floor);
180→        return shiftFloorElevationData({
181→          ...floor,
182→          name: floor.name === getDefaultFloorName(previousLevelIndex)
183→            ? getDefaultFloorName(previousLevelIndex + 1)
184→            : floor.name,
185→          levelIndex: previousLevelIndex + 1,
186→        }, elevationShift);
187→      });
188→
189→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
190→    }
191→
192→    case 'FLOOR_DELETE': {
193→      if (state.project.floors.length <= 1) return state;
194→
195→      const nextProject = replaceDeletedFloorReferences(
196→        {
197→          ...state.project,
198→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
199→        },
200→        action.floorId,
201→        action.fallbackFloorId
202→      );
203→
204→      return applyProjectUpdate(state, {
205→        ...nextProject,
206→        updatedAt: new Date().toISOString(),
207→        floors: sortFloors(nextProject.floors),
208→      });
209→    }
210→
211→    case 'SHEET_ADD':
212→      return applyProjectUpdate(state, {
213→        ...state.project,
214→        updatedAt: new Date().toISOString(),
215→        sheets: [...(state.project.sheets || []), action.sheet],
216→      });
217→
218→    case 'SHEET_UPDATE':
219→      return applyProjectUpdate(state, {
220→        ...state.project,
221→        updatedAt: new Date().toISOString(),
222→        sheets: (state.project.sheets || []).map((sheet) => (
223→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
224→        )),
225→      });
226→
227→    case 'SHEET_DELETE':
228→      return applyProjectUpdate(state, {
229→        ...state.project,
230→        updatedAt: new Date().toISOString(),
231→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
232→      });
233→
234→    case 'SHEET_VIEWPORT_ADD':
235→      return applyProjectUpdate(state, {
236→        ...state.project,
237→        updatedAt: new Date().toISOString(),
238→        sheets: (state.project.sheets || []).map((sheet) => (
239→          sheet.id === action.sheetId
240→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
241→            : sheet
242→        )),
243→      });
244→
245→    case 'SHEET_VIEWPORT_UPDATE':
246→      return applyProjectUpdate(state, {
247→        ...state.project,
248→        updatedAt: new Date().toISOString(),
249→        sheets: (state.project.sheets || []).map((sheet) => (
250→          sheet.id === action.sheetId
251→            ? {
252→                ...sheet,
253→                viewports: (sheet.viewports || []).map((viewport) => (
254→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
255→                )),
256→              }
257→            : sheet
258→        )),
259→      });
260→
261→    case 'SHEET_VIEWPORT_DELETE':
262→      return applyProjectUpdate(state, {
263→        ...state.project,
264→        updatedAt: new Date().toISOString(),
265→        sheets: (state.project.sheets || []).map((sheet) => (
266→          sheet.id === action.sheetId
267→            ? {
268→                ...sheet,
269→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
270→              }
271→            : sheet
272→        )),
273→      });
274→
275→    case 'WALL_ADD':
276→      return updateFloor(state, action.floorId, f => ({
277→        ...f,
278→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
279→      }));
280→
281→    case 'WALL_UPDATE':
282→      return updateFloor(state, action.floorId, f => {
283→        let updatedWall = null;
284→        const walls = f.walls.map((wall) => {
285→          if (wall.id !== action.wall.id) return wall;
286→
287→          updatedWall = mergeWallUpdate(wall, action.wall, f.columns || []);
288→          return updatedWall;
289→        });
290→
291→        if (!updatedWall) {
292→          return f;
293→        }
294→
295→        const nextWallLength = wallLength(updatedWall);
296→
297→        return {
298→          ...f,
299→          walls,
300→          doors: clampWallMountedOpenings(f.doors, updatedWall.id, nextWallLength),
301→          windows: clampWallMountedOpenings(f.windows, updatedWall.id, nextWallLength),
302→        };
303→      });
304→
305→    case 'WALL_DELETE': {
306→      const wallId = action.wallId;
307→      return updateFloor(state, action.floorId, f => ({
308→        ...f,
309→        walls: f.walls.filter(w => w.id !== wallId),
310→        doors: f.doors.filter(d => d.wallId !== wallId),
311→        windows: f.windows.filter(w => w.wallId !== wallId),
312→      }));
313→    }
314→
315→    case 'DOOR_ADD':
316→      return updateFloor(state, action.floorId, f => ({
317→        ...f,
318→        doors: [...f.doors, action.door],
319→      }));
320→
321→    case 'DOOR_UPDATE':
322→      return updateFloor(state, action.floorId, f => ({
323→        ...f,
324→        doors: f.doors.map(d => d.id === action.door.id ? { ...d, ...action.door } : d),
325→      }));
326→
327→    case 'DOOR_DELETE':
328→      return updateFloor(state, action.floorId, f => ({
329→        ...f,
330→        doors: f.doors.filter(d => d.id !== action.doorId),
331→      }));
332→
333→    case 'WINDOW_ADD':
334→      return updateFloor(state, action.floorId, f => ({
335→        ...f,
336→        windows: [...f.windows, action.window],
337→      }));
338→
339→    case 'WINDOW_UPDATE':
340→      return updateFloor(state, action.floorId, f => ({
341→        ...f,
342→        windows: f.windows.map(w => w.id === action.window.id ? { ...w, ...action.window } : w),
343→      }));
344→
345→    case 'WINDOW_DELETE':
346→      return updateFloor(state, action.floorId, f => ({
347→        ...f,
348→        windows: f.windows.filter(w => w.id !== action.windowId),
349→      }));
350→
351→    case 'BEAM_ADD':
352→      return updateFloor(state, action.floorId, f => ({
353→        ...f,
354→        beams: [...(f.beams || []), action.beam],
355→      }));
356→
357→    case 'BEAM_UPDATE':
358→      return updateFloor(state, action.floorId, f => ({
359→        ...f,
360→        beams: (f.beams || []).map(beam => (
361→          beam.id === action.beam.id ? { ...beam, ...action.beam } : beam
362→        )),
363→      }));
364→
365→    case 'BEAM_DELETE':
366→      return updateFloor(state, action.floorId, f => ({
367→        ...f,
368→        beams: (f.beams || []).filter(beam => beam.id !== action.beamId),
369→      }));
370→
371→    case 'STAIR_ADD':
372→      return updateFloor(state, action.floorId, f => ({
373→        ...f,
374→        stairs: [...(f.stairs || []), action.stair],
375→      }));
376→
377→    case 'STAIR_UPDATE':
378→      return updateFloor(state, action.floorId, f => ({
379→        ...f,
380→        stairs: (f.stairs || []).map(stair => (
381→          stair.id === action.stair.id ? { ...stair, ...action.stair } : stair
382→        )),
383→      }));
384→
385→    case 'STAIR_DELETE':
386→      return updateFloor(state, action.floorId, f => ({
387→        ...f,
388→        stairs: (f.stairs || []).filter(stair => stair.id !== action.stairId),
389→      }));
390→
391→    case 'LANDING_ADD':
392→      return updateFloor(state, action.floorId, f => ({
393→        ...f,
394→        landings: [...(f.landings || []), action.landing],
395→      }));
396→
397→    case 'LANDING_UPDATE': {
398→      return updateFloor(state, action.floorId, f => {
399→        const nextLandings = (f.landings || []).map(l =>
400→          l.id === action.landing.id ? { ...l, ...action.landing } : l
401→        );
402→        // Cascade: sync all stairs attached to this landing
403→        const nextStairs = (f.stairs || []).map(stair => {
404→          const attachedToStart = stair.startLandingAttachment?.landingId === action.landing.id;
405→          const attachedToEnd = stair.endLandingAttachment?.landingId === action.landing.id;
406→          if (!attachedToStart && !attachedToEnd) return stair;
407→          return syncStairLandingAttachment(stair, nextLandings);
408→        });
409→        return { ...f, landings: nextLandings, stairs: nextStairs };
410→      });
411→    }
412→
413→    case 'LANDING_DELETE':
414→      return updateFloor(state, action.floorId, f => ({
415→        ...f,
416→        landings: (f.landings || []).filter(l => l.id !== action.landingId),
417→        stairs: (f.stairs || []).map(stair => {
418→          let next = stair;
419→          if (stair.startLandingAttachment?.landingId === action.landingId) {
420→            next = { ...next, startLandingAttachment: null };
421→          }
422→          if (stair.endLandingAttachment?.landingId === action.landingId) {
423→            next = { ...next, endLandingAttachment: null };
424→          }
425→          return next;
426→        }),
427→      }));
428→
429→    case 'ANNOTATION_ADD':
430→      return updateFloor(state, action.floorId, f => ({
431→        ...f,
432→        annotations: [...(f.annotations || []), action.annotation],
433→      }));
434→
435→    case 'ANNOTATION_UPDATE':
436→      return updateFloor(state, action.floorId, f => ({
437→        ...f,
438→        annotations: (f.annotations || []).map((annotation) => (
439→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
440→        )),
441→      }));
442→
443→    case 'ANNOTATION_DELETE':
444→      return updateFloor(state, action.floorId, f => ({
445→        ...f,
446→        annotations: (f.annotations || []).filter((annotation) => annotation.id !== action.annotationId),
447→      }));
448→
449→    case 'ANNOTATION_SETTINGS_UPDATE':
450→      return updateFloor(state, action.floorId, f => ({
451→        ...f,
452→        annotationSettings: {
453→          ...(f.annotationSettings || {}),
454→          ...action.settings,
455→        },
456→      }));
457→
458→    case 'SLAB_ADD':
459→      return updateFloor(state, action.floorId, f => ({
460→        ...f,
461→        slabs: [...(f.slabs || []), action.slab],
462→      }));
463→
464→    case 'SLAB_UPDATE':
465→      return updateFloor(state, action.floorId, f => ({
466→        ...f,
467→        slabs: (f.slabs || []).map(s =>
468→          s.id === action.slab.id ? { ...s, ...action.slab } : s
469→        ),
470→      }));
471→
472→    case 'SLAB_DELETE':
473→      return updateFloor(state, action.floorId, f => ({
474→        ...f,
475→        slabs: (f.slabs || []).filter(s => s.id !== action.slabId),
476→      }));
477→
478→    case 'RAILING_ADD':
479→      return updateFloor(state, action.floorId, f => ({
480→        ...f,
481→        railings: [...(f.railings || []), action.railing],
482→      }));
483→
484→    case 'RAILING_UPDATE':
485→      return updateFloor(state, action.floorId, f => ({
486→        ...f,
487→        railings: (f.railings || []).map(r =>
488→          r.id === action.railing.id ? { ...r, ...action.railing } : r
489→        ),
490→      }));
491→
492→    case 'RAILING_DELETE':
493→      return updateFloor(state, action.floorId, f => ({
494→        ...f,
495→        railings: (f.railings || []).filter(r => r.id !== action.railingId),
496→      }));
497→
498→    case 'SECTION_ADD':
499→      return updateFloor(state, action.floorId, f => ({
500→        ...f,
501→        sectionCuts: [...(f.sectionCuts || []), action.sectionCut],
502→      }));
503→
504→    case 'SECTION_UPDATE':
505→      return updateFloor(state, action.floorId, f => ({
506→        ...f,
507→        sectionCuts: (f.sectionCuts || []).map(s =>
508→          s.id === action.sectionCut.id ? { ...s, ...action.sectionCut } : s
509→        ),
510→      }));
511→
512→    case 'SECTION_DELETE':
513→      return updateFloor(state, action.floorId, f => ({
514→        ...f,
515→        sectionCuts: (f.sectionCuts || []).filter(s => s.id !== action.sectionId),
516→      }));
517→
518→    case 'ROOM_ADD':
519→      return updateFloor(state, action.floorId, f => ({
520→        ...f,
521→        rooms: [...f.rooms, action.room],
522→      }));
523→
524→    case 'ROOM_UPDATE':
525→      return updateFloor(state, action.floorId, f => ({
526→        ...f,
527→        rooms: f.rooms.map(r => r.id === action.room.id ? { ...r, ...action.room } : r),
528→      }));
529→
530→    case 'ROOM_DELETE':
531→      return updateFloor(state, action.floorId, f => ({
532→        ...f,
533→        rooms: f.rooms.filter(r => r.id !== action.roomId),
534→      }));
535→
536→    case 'ROOMS_SET':
537→      return updateFloor(state, action.floorId, f => ({
538→        ...f,
539→        rooms: action.rooms,
540→      }));
541→
542→    case 'FLOOR_REPLACE':
543→      return updateFloor(state, action.floorId, () => ({
544→        ...action.floor,
545→      }), true, { sort: true });
546→
547→    case 'FIXTURE_ADD':
548→      return updateFloor(state, action.floorId, f => ({
549→        ...f, fixtures: [...(f.fixtures || []), action.fixture],
550→      }));
551→    case 'FIXTURE_UPDATE':
552→      return updateFloor(state, action.floorId, f => ({
553→        ...f,
554→        fixtures: (f.fixtures || []).map(fix =>
555→          fix.id === action.fixture.id ? { ...fix, ...action.fixture } : fix
556→        ),
557→      }));
558→    case 'FIXTURE_DELETE':
559→      return updateFloor(state, action.floorId, f => ({
560→        ...f,
561→        fixtures: (f.fixtures || []).filter(fix => fix.id !== action.fixtureId),
562→      }));
563→
564→    case 'COLUMN_ADD':
565→      return updateFloor(state, action.floorId, f => ({
566→        ...f, columns: [...(f.columns || []), action.column],
567→      }));
568→    case 'COLUMN_DUPLICATE':
569→      return updateFloor(state, action.floorId, f => ({
570→        ...f,
571→        columns: [...(f.columns || []), action.column],
572→      }));
573→    case 'COLUMN_UPDATE':
574→      return updateFloor(state, action.floorId, f => {
575→        const nextColumns = (f.columns || []).map(c => (
576→          c.id === action.column.id ? { ...c, ...action.column } : c
577→        ));
578→        return {
579→          ...f,
580→          columns: nextColumns,
581→          walls: f.walls.map(w => syncWallAttachmentPoints(w, nextColumns)),
582→        };
583→      });
584→    case 'COLUMN_DELETE':
585→      return updateFloor(state, action.floorId, f => ({
586→        ...f,
587→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
588→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
589→        beams: (f.beams || []).filter(beam => (
590→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
591→        )),
592→      }));
593→
594→    case 'PHASE_ADD':
595→      return applyProjectUpdate(state, {
596→        ...state.project,
597→        updatedAt: new Date().toISOString(),
598→        phases: sortPhases([...(state.project.phases || []), action.phase]),
599→      });
600→
601→    case 'PHASE_UPDATE':
602→      return applyProjectUpdate(state, {
603→        ...state.project,
604→        updatedAt: new Date().toISOString(),
605→        phases: sortPhases(
606→          (state.project.phases || []).map(p =>
607→            p.id === action.phase.id ? { ...p, ...action.phase } : p
608→          )
609→        ),
610→      });
611→
612→    case 'PHASE_DELETE': {
613→      const phaseId = action.phaseId;
614→      const nullifyPhase = (obj) =>
615→        obj.phaseId === phaseId ? { ...obj, phaseId: null } : obj;
616→      const phaseArrayKeys = [
617→        'walls', 'doors', 'windows', 'columns', 'beams', 'slabs',
618→        'stairs', 'landings', 'fixtures', 'rooms', 'railings',
619→      ];
620→      return applyProjectUpdate(state, {
621→        ...state.project,
622→        updatedAt: new Date().toISOString(),
623→        phases: (state.project.phases || []).filter(p => p.id !== phaseId),
624→        floors: state.project.floors.map(floor => {
625→          const updated = { ...floor };
626→          for (const key of phaseArrayKeys) {
627→            if (updated[key]) {
628→              updated[key] = updated[key].map(nullifyPhase);
629→            }
630→          }
631→          return updated;
632→        }),
633→        sheets: (state.project.sheets || []).map(sheet => ({
634→          ...sheet,
635→          viewports: (sheet.viewports || []).map(vp =>
636→            vp.phaseId === phaseId
637→              ? { ...vp, phaseId: null, phaseViewMode: 'all' }
638→              : vp
639→          ),
640→        })),
641→      });
642→    }
643→
644→    case 'PHASE_REORDER':
645→      return applyProjectUpdate(state, {
646→        ...state.project,
647→        updatedAt: new Date().toISOString(),
648→        phases: action.phases,
649→      });
650→
651→    case 'MARK_SAVED':
652→      return {
653→        ...state,
654→        isDirty: false,
655→        lastSavedAt: new Date().toISOString(),
656→        savedSnapshot: snapshotProject(state.project),
657→      };
658→
659→    case 'UNDO': {
660→      if (state.history.length === 0) return state;
661→      const previousProject = state.history[state.history.length - 1];
662→      return {
663→        ...state,
664→        project: previousProject,
665→        history: state.history.slice(0, -1),
666→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
667→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
668→      };
669→    }
670→
671→    case 'REDO': {
672→      if (state.future.length === 0) return state;
673→      const nextProject = state.future[0];
674→      return {
675→        ...state,
676→        project: nextProject,
677→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
678→        future: state.future.slice(1),
679→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
680→      };
681→    }
682→
683→    default:
684→      return state;
685→  }
686→}
687→
688→const initialProject = createProject();
689→
690→const initialState = {
691→  project: initialProject,
692→  isDirty: false,
693→  lastSavedAt: null,
694→  savedSnapshot: snapshotProject(initialProject),
695→  history: [],
696→  future: [],
697→};
698→
699→export function ProjectProvider({ children }) {
700→  const [state, dispatch] = useReducer(projectReducer, initialState);
701→  return (
702→    <ProjectContext.Provider value={{ state, dispatch }}>
703→      {children}
704→    </ProjectContext.Provider>
705→  );
706→}
707→
708→export function useProject() {
709→  const ctx = useContext(ProjectContext);
710→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
711→  const { state, dispatch } = ctx;
712→
713→  const duplicateFloor = (floorId) => {
714→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
715→    return floor ? createDuplicatedFloor(floor) : null;
716→  };
717→
718→  return {
719→    project: state.project,
720→    isDirty: state.isDirty,
721→    lastSavedAt: state.lastSavedAt,
722→    canUndo: state.history.length > 0,
723→    canRedo: state.future.length > 0,
724→    dispatch,
725→    duplicateFloor,
726→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
727→  };
728→}
