 79→      editorDispatch({
 80→        type: 'UPDATE_TOOL_STATE',
 81→        payload: { start: endPt, startAttachment: null, preview: null },
 82→      });
 83→    }
 84→
 85→    setDegrees('');
 86→    setMinutes('');
 87→    setLengthVal('');
 88→    setTimeout(() => lengthRef.current?.focus(), 0);
 89→  };
 90→
 91→  const handleKeyDown = (e) => {
