  8→export function deserializeProject(json) {
  9→  if (!json || !json.version || !json.data) {
 10→    throw new Error('Invalid project data');
 11→  }
 12→  if (json.version !== 1) {
 13→    throw new Error(`Unsupported project version: ${json.version}`);
 14→  }
 15→
 16→  const project = json.data;
 17→
 18→  // Basic validation
 19→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 20→    throw new Error('Invalid project structure');
 21→  }
 22→
 23→  if (!Array.isArray(project.sheets)) {
 24→    project.sheets = [];
 25→  }
 26→  if (project.address === undefined) project.address = '';
 27→  project.documentDefaults = {
 28→    drawnBy: project.documentDefaults?.drawnBy ?? '',
 29→    checkedBy: project.documentDefaults?.checkedBy ?? '',
 30→  };
 31→
 32→  if (project.floors.length === 0) {
 33→    project.floors = [createFloor('Ground Floor', 0)];
 34→  }
 35→
 36→  for (const floor of project.floors) {
 37→    if (!floor.id || !Array.isArray(floor.walls)) {
 38→      throw new Error('Invalid floor structure');
 39→    }
 40→  }
 41→
 42→  // Backfill missing room fields for old saves
 43→  project.floors.forEach((floor, index) => {
 44→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 45→    if (floor.levelIndex === undefined) {
 46→      floor.levelIndex = floor.level ?? index;
 47→    }
 48→    if (floor.floorToFloorHeight === undefined) {
 49→      floor.floorToFloorHeight = WALL_HEIGHT;
 50→    }
 51→    if (floor.elevation === undefined) {
 52→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 53→    }
 54→    delete floor.level;
 55→
 56→    if (!floor.rooms) floor.rooms = [];
 57→    for (const room of floor.rooms) {
 58→      if (!room.points) room.points = [];
 59→      if (room.area === undefined) room.area = 0;
 60→    }
 61→  });
 62→
 63→  // Backfill door/window type fields for old saves
 64→  for (const floor of project.floors) {
 65→    if (!floor.doors) floor.doors = [];
 66→    for (const door of floor.doors) {
 67→      if (!door.type) door.type = 'swing';
 68→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 69→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 70→    }
 71→    if (!floor.windows) floor.windows = [];
 72→    for (const win of floor.windows) {
 73→      if (!win.type) win.type = 'standard';
 74→      if (!win.openDirection) win.openDirection = 'left';
 75→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 76→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 77→    }
