 94→      delete floor.sectionCut;
 95→    }
 96→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
 97→    for (const wall of floor.walls) {
 98→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
 99→      if (wall.startAttachment === undefined) wall.startAttachment = null;
100→      if (wall.endAttachment === undefined) wall.endAttachment = null;
101→    }
