105→      }
106→    }
107→    for (const fixture of floor.fixtures) {
108→      if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
109→      if (fixture.x === undefined) fixture.x = 0;
110→      if (fixture.y === undefined) fixture.y = 0;
111→      if (fixture.width === undefined) fixture.width = 600;
